// Extract task from Asana webhook payload and build gateway payload with HMAC
const crypto = require('crypto');
const input = $input.item.json;

// Asana webhook sends: { events: [{ resource: { gid, name, ... }, ... }] }
// Or direct task: { data: { gid, name, notes, assignee, ... } }
let title = 'Asana task';
let description = '';
let body = input.body || input;

if (body.events && Array.isArray(body.events) && body.events.length > 0) {
  const ev = body.events[0];
  const res = ev.resource || {};
  title = res.name || title;
  description = res.notes || JSON.stringify(ev).slice(0, 2000);
} else if (body.data) {
  const d = body.data;
  title = d.name || title;
  description = d.notes || JSON.stringify(d).slice(0, 2000);
} else {
  title = body.name || body.title || title;
  description = body.notes || body.description || JSON.stringify(body).slice(0, 2000);
}

const payload = {
  title: String(title),
  description: String(description),
  priority: 'high',
  task_type: 'asana'
};

const bodyStr = JSON.stringify(payload);
const secret = $env.WEBHOOK_SECRET || '';
const sig = secret ? crypto.createHmac('sha256', secret).update(bodyStr).digest('hex') : '';

return [{ json: { _rawBody: bodyStr, _signature: sig } }];
